import{_ as a,b as o,a as t,d as r,c as i}from"./chunks/word识别结果.D4aQ-4Dz.js";import{_ as s,o as n,c as d,a2 as c}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"OCR y reconocimiento de texto","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/ocr.md","filePath":"es/Other/ocr.md","lastUpdated":1781962217000}'),l={name:"es/Other/ocr.md"};function u(p,e,h,m,b,g){return n(),d("div",null,[...e[0]||(e[0]=[c('<h1 id="ocr-y-reconocimiento-de-texto" tabindex="-1">OCR y reconocimiento de texto <a class="header-anchor" href="#ocr-y-reconocimiento-de-texto" aria-label="Permalink to &quot;OCR y reconocimiento de texto&quot;">​</a></h1><p>El OCR reconoce texto dentro de imágenes, PDF y documentos Word para facilitar la búsqueda y la revisión de contenido.</p><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes -&gt; OCR</span></span></code></pre></div><p><img src="'+a+'" alt="Ajustes OCR" loading="lazy"></p><h2 id="que-puede-hacer" tabindex="-1">Qué puede hacer <a class="header-anchor" href="#que-puede-hacer" aria-label="Permalink to &quot;Qué puede hacer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Función</th><th>Descripción</th></tr></thead><tbody><tr><td>OCR de imágenes</td><td>Lee texto en capturas o fotos</td></tr><tr><td>OCR de PDF</td><td>Extrae texto de archivos PDF</td></tr><tr><td>OCR de Word</td><td>Lee contenido de documentos Word</td></tr><tr><td>Apoyo a la búsqueda</td><td>Usa el texto reconocido como información buscable</td></tr><tr><td>Procesamiento por lotes</td><td>Procesa archivos existentes de forma masiva</td></tr></tbody></table><p><img src="'+o+'" alt="Resultado OCR" loading="lazy"></p><h2 id="preparacion" tabindex="-1">Preparación <a class="header-anchor" href="#preparacion" aria-label="Permalink to &quot;Preparación&quot;">​</a></h2><p>Según el servicio OCR que uses, necesitarás una clave API o un token. Introduce las credenciales necesarias siguiendo la interfaz.</p><p>Si usas servicios externos como PaddleOCR, comprueba que las credenciales sean correctas y que haya cuota disponible.</p><p><img src="'+t+'" alt="Obtener token" loading="lazy"></p><h2 id="como-usarlo" tabindex="-1">Cómo usarlo <a class="header-anchor" href="#como-usarlo" aria-label="Permalink to &quot;Cómo usarlo&quot;">​</a></h2><ol><li>Activa la función OCR.</li><li>Introduce la clave del servicio que vas a usar.</li><li>Guarda la configuración.</li><li>Sube archivos nuevos o ejecuta OCR sobre archivos existentes.</li><li>Revisa los resultados en el detalle del archivo o mediante búsqueda.</li></ol><p><img src="'+r+'" alt="Resultado Word" loading="lazy"></p><p><img src="'+i+'" alt="Reconocimiento PDF" loading="lazy"></p><h2 id="consejos-de-uso" tabindex="-1">Consejos de uso <a class="header-anchor" href="#consejos-de-uso" aria-label="Permalink to &quot;Consejos de uso&quot;">​</a></h2><ul><li>Las imágenes pequeñas, borrosas o inclinadas reducen la precisión.</li><li>Los PDF y Word grandes pueden tardar más en procesarse.</li><li>Si se agota la cuota de la API, el reconocimiento puede fallar.</li><li>Usa el OCR como ayuda; para información importante, revisa también el archivo original.</li></ul>',18)])])}const v=s(l,[["render",u]]);export{x as __pageData,v as default};
